command:
// =========================
// CASTLE GENERATOR
// Sandbox Generator
// Requires: Settlement Name Generator macro
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

function uniqueRolls(count, sides) {
    const results = [];
    while (results.length < count) {
        const r = roll(sides);
        if (!results.includes(r)) results.push(r);
    }
    return results;
}

// -------------------------
// NAME
// -------------------------

let settlementName = "Unknown Castle";
let settlementNameFormat = "";
let settlementNameRolls = [];

const nameMacro = game.macros.getName("Settlement Name Generator");

if (nameMacro) {
    await nameMacro.execute();
    settlementName = globalThis.generatedSettlementName ?? "Unknown Castle";
    settlementNameFormat = globalThis.generatedSettlementNameFormat ?? "";
    settlementNameRolls = globalThis.generatedSettlementNameRolls ?? [];
}

// -------------------------
// TABLES
// -------------------------

const conditions = [
    "Perfect",
"Worn",
"Worn",
"Aged",
"Aged",
"Crumbling"
];

const keepShapes = [
    "Square/Rectangle",
"Square/Rectangle",
"Square/Rectangle",
"Round",
"Round",
"Shell / hollow cylinder"
];

const keepDefensiveFeatures = [
    "None", "None", "None", "None", "None", "None",
"Ballista", "Boiling oil", "Catapult", "Hoarding",
"Iron spikes", "Piles of rocks"
];

const keepNonDefensiveFeatures = [
    "None", "None", "None", "None", "None", "None",
"Banners/Flags", "Gargoyles", "Heads/Bodies",
"Overgrown", "Religious symbols", "Secret passage"
];

const defensiveStructures = [
    { min: 1, max: 3, result: "Stone walls and towers" },
{ min: 4, max: 4, result: "Moat / trench" },
{ min: 5, max: 5, result: "Motte / mound" },
{ min: 6, max: 6, result: "Wooden palisade" }
];

const wallShapes = [
    { roll: 1, shape: "Square/Rectangle", towers: 4 },
{ roll: 2, shape: "Trapezium", towers: 4 },
{ roll: 3, shape: "Pentagon", towers: 5 },
{ roll: 4, shape: "Hexagon", towers: 6 },
{ roll: 5, shape: "Octagon", towers: 8 },
{ roll: 6, shape: "Star", towers: 10 },
{ roll: 7, shape: "Cross", towers: 12 },
{ roll: 8, shape: "Circle", towers: "1d3 + 3" }
];

const gatehouseClosures = [
    "Portcullis and wooden door",
"Portcullis and wooden door",
"Portcullis and wooden door",
"Drawbridge",
"Drawbridge",
"Both"
];

const moatEncounters = [
    "Nothing", "Nothing", "Nothing", "Nothing",
"Crocodiles", "Electric eels", "Leeches", "Piranha"
];

const dispositions = [
    { min: 2, max: 2, result: "Attack on sight" },
{ min: 3, max: 5, result: "Hostile" },
{ min: 6, max: 8, result: "Neutral" },
{ min: 9, max: 11, result: "Welcoming" },
{ min: 12, max: 12, result: "Enthusiastic" }
];

const eventTiming = [
    { min: 1, max: 1, result: "Ended earlier" },
{ min: 2, max: 4, result: "Is happening now" },
{ min: 5, max: 6, result: "Will take place in the future" }
];

const castleEvents = [
    "Assassination",
"Big monster attack",
"Ceremony / wedding, etc.",
"Festival/Fair",
"Fire",
"Plague",
"Resources/Gold dwindling",
"Rival lord scouting",
"Siege/Looting",
"Small monsters wanting to establish a lair nearby",
"Tournament",
"Visit of a notable person"
];

const troopTypes = [
    "Cavaliers: heavy horse, plate & shield, sword",
"Cavaliers: medium horse, plate & shield, spear",
"Cavaliers: medium horse, chainmail, short bow",
"Footmen: chainmail & shield, sword",
"Footmen: chainmail, polearm",
"Footmen: chainmail, crossbow",
"Footmen: chainmail, longbow"
];

// -------------------------
// ROLLS
// -------------------------

let conditionRoll = roll(6);
let condition = conditions[conditionRoll - 1];

let keepLevelRoll = roll(3);
let keepLevels = keepLevelRoll + 1;

let keepShapeRoll = roll(6);
let keepShape = keepShapes[keepShapeRoll - 1];

let keepDefRoll = roll(12);
let keepDefFeature = keepDefensiveFeatures[keepDefRoll - 1];

let keepNonDefRoll = roll(12);
let keepNonDefFeature = keepNonDefensiveFeatures[keepNonDefRoll - 1];

let jailCommonersRoll1 = roll(6);
let jailCommonersRoll2 = roll(6);
let jailCommoners = jailCommonersRoll1 + jailCommonersRoll2;

let jailNoblesRoll = roll(3);
let jailNobles = jailNoblesRoll;

let supplyRoll1 = roll(6);
let supplyRoll2 = roll(6);
let supplyMonths = supplyRoll1 + supplyRoll2;

let defensiveStructureCountRoll = roll(4);
let defensiveStructureCount = defensiveStructureCountRoll;

let defensiveRolls = uniqueRolls(defensiveStructureCount, 6);
let defensiveResults = defensiveRolls.map(r => ({
    roll: r,
    result: tableRoll(r, defensiveStructures).result
}));

let hasWalls = defensiveResults.some(d => d.result === "Stone walls and towers");
let hasMoat = defensiveResults.some(d => d.result === "Moat / trench");

let wallShapeRoll = null;
let wallShape = null;
let towerCount = null;
let towerCountRoll = null;
let wallDefRoll = null;
let wallDefFeature = null;
let wallNonDefRoll = null;
let wallNonDefFeature = null;
let gatehouseRoll = null;
let gatehouseClosure = null;

if (hasWalls) {
    wallShapeRoll = roll(8);
    let wallData = wallShapes.find(w => w.roll === wallShapeRoll);
    wallShape = wallData.shape;

    if (wallData.towers === "1d3 + 3") {
        towerCountRoll = roll(3);
        towerCount = towerCountRoll + 3;
    } else {
        towerCount = wallData.towers;
    }

    wallDefRoll = roll(12);
    wallDefFeature = keepDefensiveFeatures[wallDefRoll - 1];

    wallNonDefRoll = roll(12);
    wallNonDefFeature = keepNonDefensiveFeatures[wallNonDefRoll - 1];

    gatehouseRoll = roll(6);
    gatehouseClosure = gatehouseClosures[gatehouseRoll - 1];
}

let moatRoll = null;
let moatEncounter = null;

if (hasMoat) {
    moatRoll = roll(8);
    moatEncounter = moatEncounters[moatRoll - 1];
}

let garrisonRoll = 0;
let garrisonDice = [];

for (let i = 0; i < 3; i++) {
    let r = roll(6);
    garrisonDice.push(r);
    garrisonRoll += r;
}

let fighters = garrisonRoll * 10;

let lordLevel = 9 + Math.floor(fighters / 60);
let lieutenantLevel = lordLevel - 2;
let bodyguardLevel = lordLevel - 3;

let troops = [
    Math.round(fighters * 0.10),
    Math.round(fighters * 0.10),
    Math.round(fighters * 0.10),
    Math.round(fighters * 0.40),
    Math.round(fighters * 0.10),
    Math.round(fighters * 0.10),
    Math.round(fighters * 0.10)
];

let dispositionDie1 = roll(6);
let dispositionDie2 = roll(6);
let dispositionTotal = dispositionDie1 + dispositionDie2;
let disposition = tableRoll(dispositionTotal, dispositions).result;

let eventCheckRoll = roll(6);
let hasEvent = eventCheckRoll === 1;

let eventTimingRoll = null;
let eventTime = "None";
let eventRoll = null;
let castleEvent = "None";

if (hasEvent) {
    eventTimingRoll = roll(6);
    eventTime = tableRoll(eventTimingRoll, eventTiming).result;

    eventRoll = roll(12);
    castleEvent = castleEvents[eventRoll - 1];
}

// Treasure
let gpTreasureRoll = roll(100);
let gpTreasure = "None";
let gpRoll = null;

if (gpTreasureRoll <= 50) {
    gpRoll = roll(4);
    gpTreasure = `${gpRoll * 10000} gp`;
} else {
    gpRoll = roll(6);
    gpTreasure = `${gpRoll * 5000} gp`;
}

let gemCheck = roll(100);
let gemRolls = [];
let gems = 0;

if (gemCheck <= 25) {
    for (let i = 0; i < 3; i++) {
        let r = roll(6);
        gemRolls.push(r);
        gems += r;
    }
}

let jewelryCheck = roll(100);
let jewelryRoll = null;
let jewelry = 0;

if (jewelryCheck <= 25) {
    jewelryRoll = roll(10);
    jewelry = jewelryRoll;
}

let magicCheck = roll(100);
let scrollRoll = null;
let magicItems = 0;
let scrolls = 0;

if (magicCheck <= 15) {
    magicItems = 4;
    scrollRoll = roll(6);
    scrolls = scrollRoll;
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Castle Generator</h2>

<h3>Castle Name</h3>
<p><b>Name:</b> ${settlementName}</p>
<p><b>Format:</b> ${settlementNameFormat}</p>
<ul>
${settlementNameRolls.map(r => `<li>${r}</li>`).join("")}
</ul>

<hr>

<h3>General Condition</h3>
<p><b>Condition Roll:</b> d6 = ${conditionRoll}</p>
<p><b>Condition:</b> ${condition}</p>

<hr>

<h3>Keep</h3>
<p><b>Keep Levels Roll:</b> d3 + 1 = ${keepLevelRoll} + 1</p>
<p><b>Keep Levels:</b> ${keepLevels}</p>

<p><b>Keep Shape Roll:</b> d6 = ${keepShapeRoll}</p>
<p><b>Keep Shape:</b> ${keepShape}</p>

<p><b>Keep Defensive Feature Roll:</b> d12 = ${keepDefRoll}</p>
<p><b>Keep Defensive Feature:</b> ${keepDefFeature}</p>

<p><b>Keep Non-Defensive Feature Roll:</b> d12 = ${keepNonDefRoll}</p>
<p><b>Keep Non-Defensive Feature:</b> ${keepNonDefFeature}</p>

<p><b>Jail Commoners Roll:</b> 2d6 = ${jailCommonersRoll1} + ${jailCommonersRoll2} = ${jailCommoners}</p>
<p><b>Jailed Commoners:</b> ${jailCommoners}</p>

<p><b>Jail Nobles Roll:</b> d3 = ${jailNoblesRoll}</p>
<p><b>Jailed Nobles:</b> ${jailNobles}</p>

<p><b>Supplies Roll:</b> 2d6 = ${supplyRoll1} + ${supplyRoll2} = ${supplyMonths}</p>
<p><b>Supplies:</b> Enough food and water for ${supplyMonths} month${supplyMonths === 1 ? "" : "s"}.</p>

<hr>

<h3>Defenses</h3>
<p><b>Number of Defensive Structures Roll:</b> d4 = ${defensiveStructureCountRoll}</p>
<p><b>Defensive Structures:</b></p>
<ul>
${defensiveResults.map(d => `<li>d6 = ${d.roll} → ${d.result}</li>`).join("")}
</ul>

${hasWalls ? `
    <h4>Walls & Towers</h4>
    <p><b>Wall Shape Roll:</b> d8 = ${wallShapeRoll}</p>
    <p><b>Wall Shape:</b> ${wallShape}</p>
    <p><b>Towers:</b> ${towerCount}${towerCountRoll ? ` (d3 + 3 = ${towerCountRoll} + 3)` : ""}</p>

    <p><b>Wall Defensive Feature Roll:</b> d12 = ${wallDefRoll}</p>
    <p><b>Wall Defensive Feature:</b> ${wallDefFeature}</p>

    <p><b>Wall Non-Defensive Feature Roll:</b> d12 = ${wallNonDefRoll}</p>
    <p><b>Wall Non-Defensive Feature:</b> ${wallNonDefFeature}</p>

    <p><b>Gatehouse Roll:</b> d6 = ${gatehouseRoll}</p>
    <p><b>Gatehouse Closure:</b> ${gatehouseClosure}</p>
    ` : `<p><i>No stone walls and towers were generated.</i></p>`}

    ${hasMoat ? `
        <h4>Moat</h4>
        <p><b>Moat Encounter Roll:</b> d8 = ${moatRoll}</p>
        <p><b>Moat Encounter:</b> ${moatEncounter}</p>
        ` : `<p><i>No moat was generated.</i></p>`}

        <hr>

        <h3>Garrison</h3>
        <p><b>Garrison Roll:</b> 3d6 × 10 = (${garrisonDice.join(" + ")}) × 10 = ${fighters}</p>
        <p><b>Total Fighters:</b> ${fighters}</p>

        <ul>
        ${troopTypes.map((type, i) => `<li><b>${type}:</b> ${troops[i]}</li>`).join("")}
        </ul>

        <p><b>Lord Level:</b> ${lordLevel}</p>
        <p><b>Lieutenant Level:</b> ${lieutenantLevel}</p>
        <p><b>Bodyguards:</b> 6 bodyguards, level ${bodyguardLevel}</p>

        <hr>

        <h3>Disposition</h3>
        <p><b>Disposition Roll:</b> 2d6 = ${dispositionDie1} + ${dispositionDie2} = ${dispositionTotal}</p>
        <p><b>Disposition:</b> ${disposition}</p>

        <hr>

        <h3>Event</h3>
        <p><b>Event Check:</b> d6 = ${eventCheckRoll}</p>
        <p><b>Has Event:</b> ${hasEvent ? "Yes" : "No"}</p>
        ${hasEvent ? `
            <p><b>Event Timing Roll:</b> d6 = ${eventTimingRoll}</p>
            <p><b>Timing:</b> ${eventTime}</p>
            <p><b>Event Roll:</b> d12 = ${eventRoll}</p>
            <p><b>Event:</b> ${castleEvent}</p>
            ` : `<p><b>Event:</b> None</p>`}

            <hr>

            <h3>Treasure</h3>
            <p><b>Gold Treasure Roll:</b> d100 = ${gpTreasureRoll}</p>
            <p><b>Gold Formula Roll:</b> ${gpTreasureRoll <= 50 ? `d4 = ${gpRoll} × 10000` : `d6 = ${gpRoll} × 5000`}</p>
            <p><b>Gold:</b> ${gpTreasure}</p>

            <p><b>Gems Check:</b> d100 = ${gemCheck}</p>
            <p><b>Gems:</b> ${gemCheck <= 25 ? `Yes, 3d6 = ${gemRolls.join(" + ")} = ${gems} gems` : "No"}</p>

            <p><b>Jewelry Check:</b> d100 = ${jewelryCheck}</p>
            <p><b>Jewelry:</b> ${jewelryCheck <= 25 ? `Yes, d10 = ${jewelryRoll} pieces` : "No"}</p>

            <p><b>Magic Treasure Check:</b> d100 = ${magicCheck}</p>
            <p><b>Magic Treasure:</b> ${magicCheck <= 15 ? `Yes, ${magicItems} magic items + d6 scrolls = ${scrollRoll} scrolls` : "No"}</p>

            <hr>

            <h3>Quick Summary</h3>
            <p>
            <b>${settlementName}</b> is a <b>${condition.toLowerCase()}</b> castle with a
            <b>${keepLevels}-level ${keepShape.toLowerCase()}</b> keep.
            It is defended by <b>${fighters}</b> fighters under a level <b>${lordLevel}</b> lord.
            ${hasWalls ? `Its walls are <b>${wallShape.toLowerCase()}</b> with <b>${towerCount}</b> tower${towerCount === 1 ? "" : "s"}.` : "It has no stone wall enclosure."}
            ${hasMoat ? ` Its moat contains: <b>${moatEncounter}</b>.` : ""}
            The castle’s inhabitants are <b>${disposition.toLowerCase()}</b>.
            ${hasEvent ? ` Current event: <b>${castleEvent}</b> — ${eventTime.toLowerCase()}.` : ""}
            Treasure includes <b>${gpTreasure}</b>${gems ? `, ${gems} gems` : ""}${jewelry ? `, ${jewelry} pieces of jewelry` : ""}${magicItems ? `, ${magicItems} magic items and ${scrolls} scrolls` : ""}.
            </p>
            `;
            if (globalThis.currentHexFaction) {
                output += `
                <hr>

                <h3>Faction</h3>

                <p><b>Controlling Faction:</b></p>
                <p>${globalThis.currentHexFaction}</p>
                `;
            }
            ChatMessage.create({
                speaker: ChatMessage.getSpeaker(),
                               content: output
            });
